// Example 1: Basic single-directional circular pattern with equal spacing
using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;

ModelDoc2 swModel = /* ... */;
FeatureManager swFeatureManager = (FeatureManager)swModel.FeatureManager;
ModelDocExtension swModelDocExt = (ModelDocExtension)swModel.Extension;

// Pre-select axis (mark 1) and feature (mark 4) - ORDER MATTERS
bool status = swModelDocExt.SelectByID2("Edge1", "EDGE", 0, 0, 0, false, 1, null, 0);
status = swModelDocExt.SelectByID2("Boss-Extrude1", "BODYFEATURE", 0, 0, 0, false, 4, null, 0);

// Create pattern definition - captures pre-selections automatically
CircularPatternFeatureData circPattern = (CircularPatternFeatureData)
    swFeatureManager.CreateDefinition((int)swFeatureNameID_e.swFmCirPattern);

// Configure for 6 equal instances around full circle
circPattern.TotalInstances = 6;
circPattern.EqualSpacing = true;
circPattern.Spacing = 2 * Math.PI;  // TOTAL ANGLE (full circle) when EqualSpacing=true
circPattern.BodyPattern = false;
circPattern.GeometryPattern = false;

Feature feature = (Feature)swFeatureManager.CreateFeature(circPattern);
```

