// - Mark 1: Direction axis (edge, axis, or cylindrical face)
// - Mark 4: Seed features to pattern

// Step 2: Create the feature data object
ICircularPatternFeatureData cirPatternData = (ICircularPatternFeatureData)featureManager.CreateDefinition((int)swFeatureNameID_e.swFmCirPattern);

// Step 3: Configure for single-directional pattern with unequal spacing
cirPatternData.BodyPattern = false;  // false: pattern features/faces; true: pattern bodies
cirPatternData.Direction2 = false;  // Single direction only

// CRITICAL: EqualSpacing controls how Spacing parameter is interpreted
cirPatternData.EqualSpacing = false;  
// - true: Spacing = total angle (in radians) to distribute all instances
// - false: Spacing = angle (in radians) BETWEEN consecutive instances
// Setting false does NOT create varied spacing; it changes spacing interpretation

cirPatternData.Spacing = <double>;  // Angle in radians (between instances when EqualSpacing=false)
cirPatternData.TotalInstances = <int>;  // Total instances including seed
cirPatternData.ReverseDirection = <bool>;  // Optional: reverse axis direction

// For per-instance spacing customization (requires GeometryPattern=false):
cirPatternData.GeometryPattern = false;  // MUST be false to enable InstancesToVary
cirPatternData.PropagateVisualProperty = <bool>;  // Optional: propagate colors/textures

// Step 4: Create the feature
IFeature feature = featureManager.CreateFeature(cirPatternData);

// Step 5: To vary individual instance spacing (post-creation modification):
if (feature != null) {
    cirPatternData = (ICircularPatternFeatureData)feature.GetDefinition();
    cirPatternData.AccessSelections(swModel, null);
    cirPatternData.InstancesToVary = true;  // Enable per-instance customization
    feature.ModifyDefinition(cirPatternData, swModel, null);

    // Configure individual instance spacing
    IInstanceToVaryOptions varyOpts = cirPatternData.GetInstanceToVaryOptions();
    varyOpts.D1SpacingIncrement = <double>;  // Incremental spacing for all instances
    varyOpts.ModifyD1SpacingValue(<int instance>, <double spacing>);  // Custom spacing for specific instance
    cirPatternData.SetInstanceToVaryOptions(varyOpts);
    feature.ModifyDefinition(cirPatternData, swModel, null);
}

