using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;
using System;

// Assume swModel is ModelDoc2, swApp is SldWorks
ModelDocExtension swModelDocExt = (ModelDocExtension)swModel.Extension;
FeatureManager swFeatureManager = (FeatureManager)swModel.FeatureManager;

// Step 1: Pre-select ONLY the axis (edge or reference axis) with mark=1
// Faces will be set programmatically, NOT pre-selected
bool status = swModelDocExt.SelectByID2(
    "Edge<1>", "EDGE", 0, 0, 0, false, 1, null, 0);
// OR use SelectByRay to select axis
// status = swModelDocExt.SelectByRay(0.029, 0.021, 0.060, 0.342, -0.159, -0.926, 0.0009, 1, true, 1, 0);

// Step 2: Obtain faces to pattern (via traversal or selection)
// Example: Get faces from a feature
Feature seedFeature = ...;  // Obtain feature
object[] facesToPattern = ...;  // Obtain array of IFace2 objects from feature

// Step 3: Create circular pattern feature data
CircularPatternFeatureData swCircPatternData = 
    (CircularPatternFeatureData)swFeatureManager.CreateDefinition(
        (int)swFeatureNameID_e.swFmCirPattern);

// Step 4: Configure face-based pattern
swCircPatternData.PatternElement = (int)swPatternElementSelection_e.swFeatureFaces;  // 1
swCircPatternData.BodyPattern = false;  // Face-based, not body-based
swCircPatternData.PatternFaceArray = facesToPattern;  // Set faces programmatically

// Step 5: Configure single-directional with equal spacing
swCircPatternData.TotalInstances = 4;     // 4 total instances (1 seed + 3 copies)
swCircPatternData.EqualSpacing = true;    // Enable equal spacing

// CRITICAL: When EqualSpacing = true, Spacing = TOTAL ANGLE in radians
// For 4 instances equally spaced over 90 degrees:
swCircPatternData.Spacing = Math.PI / 2;  // 90 degrees in radians (TOTAL ANGLE)
                                           // Each instance separated by ~30 degrees

swCircPatternData.ReverseDirection = false;  // Don't reverse axis
swCircPatternData.Direction2 = false;        // Single-directional

// Step 6: Create the feature
Feature swFeature = swFeatureManager.CreateFeature(swCircPatternData);

// Step 7: Verify and retrieve properties
if (swFeature != null)
{
    swCircPatternData = (CircularPatternFeatureData)swFeature.GetDefinition();
    Debug.Print("Pattern created with " + swCircPatternData.TotalInstances + " instances");
    Debug.Print("Total angle (radians): " + swCircPatternData.Spacing);
    Debug.Print("Total angle (degrees): " + (swCircPatternData.Spacing * 180.0 / Math.PI));
    Debug.Print("Equal spacing enabled: " + swCircPatternData.EqualSpacing);
}

// Example 2: Pattern with spacing between instances (EqualSpacing = false)
swCircPatternData.EqualSpacing = false;     // Disable equal spacing
swCircPatternData.Spacing = Math.PI / 6;    // 30 degrees BETWEEN each instance (in radians)
swCircPatternData.TotalInstances = 4;       // Will span 90 degrees total (3 gaps × 30°)
