// Example: Create bidirectional circular pattern with equal spacing
// IMPORTANT: When EqualSpacing=true, Spacing is the TOTAL angle, not inter-instance spacing
// With 4 instances over π/2 radians: instances at 0°, 30°, 60°, 90° (not 0°, 90°, 180°, 270°)

// Pre-select the feature to pattern (mark 4)
bool status = modelDocExt.SelectByID2(
    "Boss-Extrude2", "BODYFEATURE", 
    -0.0000568552547690615, 0.0336059294503599, 0.0699999999999932, 
    false, 4, null, 0);

// Pre-select the rotation axis (mark 1 for axis)
status = modelDocExt.SelectByRay(
    0.0289184346104037, 0.0205122863998071, 0.0598787397922251,
    0.342497149434059, -0.159204982974168, -0.925931679998983,
    0.000912809005339891, 1, true, 1, 0);

// Create the circular pattern feature data
var circPatternData = (CircularPatternFeatureData)featureManager.CreateDefinition(
    (int)swFeatureNameID_e.swFmCirPattern);

// Configure bidirectional with equal spacing in both directions
circPatternData.Direction2 = true;      // Enable bidirectional
circPatternData.Symmetric = false;      // REQUIRED for EqualSpacing2 to work

// Direction 1: 4 instances equally distributed over π/2 radians total
circPatternData.EqualSpacing = true;    // Equal spacing in Direction 1
circPatternData.TotalInstances = 4;     // 4 instances total
circPatternData.Spacing = Math.PI / 2;  // Total span: π/2 radians (90°)
                                         // Instances at: 0°, 30°, 60°, 90°

// Direction 2: 4 instances equally distributed over π/2 radians total
circPatternData.EqualSpacing2 = true;   // Equal spacing in Direction 2
circPatternData.TotalInstances2 = 4;    // 4 instances in Direction 2
circPatternData.Spacing2 = Math.PI / 2; // Total span: π/2 radians (90°)

// Create the feature
var feature = featureManager.CreateFeature(circPatternData);

// Verify the created pattern
var verifyData = (CircularPatternFeatureData)feature.GetDefinition();
Debug.Print($"Direction 1: {verifyData.TotalInstances} instances over {verifyData.Spacing} radians");
if (verifyData.Direction2)
{
    Debug.Print($"Direction 2: {verifyData.TotalInstances2} instances over {verifyData.Spacing2} radians");
    Debug.Print($"Symmetric: {verifyData.Symmetric}, EqualSpacing2: {verifyData.EqualSpacing2}");
}

