// Example 1: Create a simple blind straight slot with explicit diameter
// Note: Value1 (screw fit) is -1 because diameter is explicitly specified
using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;

// ... model and feature manager initialization ...

// Select the face where to create the slot
swModelDocExt.SelectByID2("", "FACE", -0.00061, 0.03962, -0.00830, false, 0, null, 0);

int slotType = (int)swWzdGeneralHoleTypes_e.swWzdHoleSlot;  // 8
int standardIdx = (int)swWzdHoleStandards_e.swStandardAnsiInch;
int fastenerIdx = (int)swWzdHoleStandardFastenerTypes_e.swStandardAnsiInchAllDrillSizes;
string size = "#97";
short endType = (int)swEndConditions_e.swEndCondBlind;

// Conversion factors
double convLength = 25.4 / 1000;  // inches to meters
double convAngle = Math.PI / 180.0;

// Slot parameters
double diameter = 0.5 * convLength;   // slot width (circular end diameter)
double depth = 2.0 * convLength;      // depth for blind slot
double length = 3.0 * convLength;     // slot rectangular extension

Feature slot = (Feature)swFeatureMgr.HoleWizard5(
    slotType, standardIdx, fastenerIdx, size, endType,
    diameter, depth, length,
    -1,                           // Value1: screw fit MUST be -1 when diameter specified
    118 * convAngle,              // Value2: drill angle (default: 2.05948851735331 rad)
    -1, -1, -1, -1, -1,           // Value3-7: countersink params (ignored)
    -1, -1, -1, -1, -1,           // Value8-12: unused
    "", false, false, false, false, false, false
);

// Access slot properties
WizardHoleFeatureData2 slotData = (WizardHoleFeatureData2)slot.GetDefinition();
Debug.Print("Slot length: " + slotData.Length);

// Example 2: Create a through-all straight slot
endType = (int)swEndConditions_e.swEndCondThroughAll;
depth = -1;  // not used for through-all

slot = (Feature)swFeatureMgr.HoleWizard5(
    slotType, standardIdx, fastenerIdx, size, endType,
    diameter, depth, length,
    -1, -1, -1, -1, -1, -1, -1,   // Value1-7: all ignored or default
    -1, -1, -1, -1, -1,           // Value8-12: unused
    "", false, false, false, false, false, false
);

