double depth = 0.015;              // 15mm blind depth
double cbDiameter = 0.012;         // 12mm counterbore diameter
double cbDepth = 0.005;            // 5mm counterbore depth
double nearCsinkDia = 0.010;       // 10mm near-side countersink diameter
double nearCsinkAngle = 1.309;     // 75 degrees = 1.309 radians (82° typical for flat head)

Feature hole = featureManager.HoleWizard5(
