    -1,                              // Value4: Screw fit (NORMAL_FIT default)
    -1,                              // Value5: Drill angle (118° default)
                                     //         Valid only if EndType != swEndCondUpToNext/ThroughAll
    nearCsinkDia,                    // Value6: Near countersink diameter - REQUIRED
    nearCsinkAngle,                  // Value7: Near countersink angle - REQUIRED  
