// Example: Create M10 socket head cap screw counterbored hole with far-side countersink
// This creates a through-hole with counterbore on top and 90° countersink on bottom

using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;

ModelDoc2 swModel = swApp.ActiveDoc;
FeatureManager swFeatMgr = swModel.FeatureManager;
ModelDocExtension swModelDocExt = swModel.Extension;

// Select the face for hole placement
swModelDocExt.SelectByID2("Face1", "FACE", 0, 0, 0, false, 0, null, 0);

// Create counterbored through-hole with far-side countersink
Feature swHole = swFeatMgr.HoleWizard5(
    (int)swWzdGeneralHoleTypes_e.swWzdCounterBore,              // Counterbore type
    (int)swWzdHoleStandards_e.swStandardISO,                    // ISO standard
    (int)swWzdHoleStandardFastenerTypes_e.swStandardISOSocketHeadCapScrew,
    "M10",                                                       // M10 fastener size
    (int)swEndConditions_e.swEndCondThroughAll,                 // Through-all end condition
    0.0, 0.0, 0.0,                                               // Ignored (database-driven)

    // Counterbore parameters with far-side countersink:
    17.0e-3,                                                     // Value1: Counterbore diameter 17mm
    10.0e-3,                                                     // Value2: Counterbore depth 10mm
    0.5e-3,                                                      // Value3: Head clearance 0.5mm added to depth
    (double)swWzdHoleScrewClearanceTypes_e.swScrewClearanceNormal, // Value4: Normal fit
    2.0603834,                                                   // Value5: 118° drill angle (optional)
    -1,                                                           // Value6: Near csink diameter (not used)
    -1,                                                           // Value7: Near csink angle (not used)
    -1,                                                           // Value8: Bot/underhead csink dia (not used)
    -1,                                                           // Value9: Bot/underhead csink angle (not used)
    20.0e-3,                                                     // Value10: Far csink diameter 20mm (bottom side)
    1.5707963,                                                   // Value11: Far csink angle 90° = π/2 radians
    -1,                                                           // Value12: Offset (not used)

    "",            // ThreadClass (not applicable for metric)
    false,         // RevDir
    false,         // FeatureScope
    true,          // AutoSelect
    false,         // AssemblyFeatureScope
    true,          // AutoSelectComponents
    false          // PropagateFeatureToParts
);

if (swHole != null) {
    // Access feature data to verify parameters
    WizardHoleFeatureData2 holeData = (WizardHoleFeatureData2)swHole.GetDefinition();
    Debug.WriteLine($"Through-hole diameter: {holeData.ThruHoleDiameter * 1000} mm");
    Debug.WriteLine($"Counterbore diameter: {holeData.CounterBoreDiameter * 1000} mm");
    Debug.WriteLine($"Far countersink diameter: {holeData.FarCounterSinkDiameter * 1000} mm");
    Debug.WriteLine($"Far countersink angle: {holeData.FarCounterSinkAngle * 180 / Math.PI} degrees");
}

