// Helper function for COM interop
private DispatchWrapper[] ObjectArrayToDispatchWrapperArray(object[] objects)
{
    DispatchWrapper[] wrapped = new DispatchWrapper[objects.Length];
    for (int i = 0; i < objects.Length; i++)
    {
        wrapped[i] = new DispatchWrapper(objects[i]);
    }
    return wrapped;
}

