    ThinThickness2: 0,            // double - IGNORED when ThinType is swThinWallMidPlane
    Merge: false,                 // bool - merge into multi-body part
    UseFeatScope: false,          // bool - feature affects only selected bodies
    UseAutoSelect: true           // bool - auto-select affected bodies
);

