// Type uses swRevolveType_e enum and controls revolution direction (one-dir, two-dir, mid-plane)
// ThinWallType uses swThinWallType_e enum and controls wall thickness offset direction

revolveDef.ReleaseSelectionAccess();
revolveFeat.ModifyDefinition(revolveDef, swModel, null);
