// Create a revolve feature affecting specific bodies in multibody part
// REQUIRED SELECTIONS BEFORE CALLING:
// - Sketch to revolve (Mark 0)
// - Axis of revolution (Mark 4 or 16): IRefAxis, IEdge, or ISketchSegment
// - [Optional] Up-to/offset entity (Mark 32): face, plane, or surface if using up-to-selection or offset end conditions
// - [REQUIRED for this case] Specific bodies to affect (Mark 1): pre-select IBody2 objects when UseFeatScope=true AND UseAutoSelect=false

IFeature feature = featureManager.FeatureRevolve2(
    true,           // SingleDir: true for single direction, false for bidirectional
    true,           // IsSolid: true for solid, false otherwise
    false,          // IsThin: true for thin revolve (requires ThinType/ThinThickness), false for solid
    false,          // IsCut: true for cut revolve, false for boss revolve
    false,          // ReverseDir: true to reverse angle direction (ignored if Dir1Type=swEndCondMidPlane)
    false,          // BothDirectionUpToSameEntity: true if both directions use same end entity (only when SingleDir=false and using up-to/offset conditions)
    0,              // Dir1Type: swEndConditions_e (0=swEndCondBlind, 6=swEndCondMidPlane, 10=swEndCondUpToSelection, 5=swEndCondOffsetFromSurface, 1=swEndCondThroughAll, 2=swEndCondThroughNext)
    0,              // Dir2Type: swEndConditions_e for direction 2 (ignored if SingleDir=true or Dir1Type=swEndCondMidPlane)
    6.28318530718,  // Dir1Angle: angle in radians (2*PI for 360 degrees); only used if Dir1Type=swEndCondBlind
    0,              // Dir2Angle: angle in radians for direction 2; only used if Dir2Type=swEndCondBlind
    false,          // OffsetReverse1: true to reverse offset direction 1; only if Dir1Type=swEndCondOffsetFromSurface
    false,          // OffsetReverse2: true to reverse offset direction 2; only if Dir2Type=swEndCondOffsetFromSurface
    0.01,           // OffsetDistance1: offset distance for direction 1; only if Dir1Type=swEndCondOffsetFromSurface
    0.01,           // OffsetDistance2: offset distance for direction 2; only if Dir2Type=swEndCondOffsetFromSurface
    0,              // ThinType: swThinWallType_e (0=swThinWallOneDirection, 1=swThinWallOppDirection, 2=swThinWallMidPlane, 3=swThinWallTwoDirection); use 0 for solid revolve
    0,              // ThinThickness1: wall thickness direction 1 (if ThinType=swThinWallMidPlane, thickness is divided: value/2 each direction)
    0,              // ThinThickness2: wall thickness direction 2 (only used if ThinType=swThinWallTwoDirection)
    true,           // Merge: true to merge results into multibody part, false to keep separate bodies
    true,           // UseFeatScope: TRUE for this case - feature affects only selected bodies, false affects all bodies
    false           // UseAutoSelect: FALSE for this case - use manually pre-selected bodies (Mark 1), true to auto-select all bodies
);

// To modify feature after creation:
IRevolveFeatureData2 revolveData = (IRevolveFeatureData2)feature.GetDefinition();
revolveData.AccessSelections(modelDoc, null);  // Required before modifying selections; null component for parts

// Properties synchronized with FeatureRevolve2 parameters:
revolveData.FeatureScope = true;    // Matches UseFeatScope parameter
revolveData.AutoSelect = false;     // Matches UseAutoSelect parameter; ONLY available when FeatureScope=true
revolveData.Merge = true;           // Matches Merge parameter

// Modify which bodies are affected (requires AccessSelections first):
object[] bodiesArray = { body1, body2, body3 };  // Array of IBody2 objects
revolveData.FeatureScopeBodies = bodiesArray;    // Set/change affected bodies
int bodyCount = revolveData.GetFeatureScopeBodiesCount();  // Get count
object[] currentBodies = (object[])revolveData.FeatureScopeBodies;  // Get current bodies

// Other properties:
revolveData.Type = 0;  // swRevolveType_e: 0=swRevolveTypeOneDirection, 1=swRevolveTypeMidPlane, 2=swRevolveTypeTwoDirection, 3=swRevolveTypeOneDirection360Degrees, 4=swRevolveTypeMidPlane360Degrees, 5=swRevolveTypeTwoDirection360Degrees
revolveData.ReverseDirection = false;
revolveData.Axis = axisObject;  // IRefAxis, IEdge, or ISketchSegment

// Commit changes:
feature.ModifyDefinition(revolveData, modelDoc, null);
// Note: ModifyDefinition automatically calls ReleaseSelectionAccess
// If not modifying: revolveData.ReleaseSelectionAccess() to restore rollback state

// IGNORED properties for part revolves (used only in assembly context):
// - AssemblyFeatureScope: for assembly revolve features
