// Example: Modify mirror pattern to use a different plane and update seed features
var swModel = swApp.ActiveDoc as ModelDoc2;
var mirrorFeature = swModel.FeatureManager.GetFeatureByName("Mirror1");
var mirrorData = (IMirrorPatternFeatureData)mirrorFeature.GetDefinition();

// CRITICAL: Enter rollback state - must complete with ModifyDefinition or ReleaseSelectionAccess
bool status = mirrorData.AccessSelections(swModel, null);
if (!status) {
    // Handle error - could not enter rollback state
    return;
}

try {
    // Change the mirror plane to a new reference plane
    var newPlane = swModel.FeatureManager.GetFeatureByName("Plane2");
    mirrorData.Plane = newPlane;  // for reference plane
    // OR: mirrorData.Plane = (Entity)someFace2Object;  // for face

    // Update the list of features to be mirrored
    var feature1 = swModel.FeatureManager.GetFeatureByName("Boss-Extrude1");
    var feature2 = swModel.FeatureManager.GetFeatureByName("Pocket1");
    mirrorData.PatternFeatureArray = new object[] { feature1, feature2 };

    // Enable geometry pattern mode for all bodies in multibody part
    mirrorData.GeometryPattern = true;
    mirrorData.FeatureScope = (int)swFeatureScope_e.swFeatureScope_AllBodies;

    // Apply the modifications and restore rollback state
    status = mirrorFeature.ModifyDefinition(mirrorData, swModel, null);

    // IMPORTANT: Check for errors even if status is true
    if (status) {
        int errorCode = mirrorFeature.GetErrorCode2();
        if (errorCode != 0) {
            // Feature has rebuild errors despite returning true
            Debug.Print($"Mirror feature has rebuild error: {errorCode}");
            swModel.ForceRebuild3(false);  // Attempt to correct
        }
    } else {
        Debug.Print("ModifyDefinition failed");
    }
} catch (Exception ex) {
    // If modification fails, cancel and restore rollback state
    mirrorData.ReleaseSelectionAccess();
    throw;
}

// Example: Modify feature scope to selected bodies
var mirrorFeature2 = swModel.FeatureManager.GetFeatureByName("Mirror2");
var mirrorData2 = (IMirrorPatternFeatureData)mirrorFeature2.GetDefinition();
mirrorData2.AccessSelections(swModel, null);

mirrorData2.GeometryPattern = true;  // Required for FeatureScope
mirrorData2.FeatureScope = (int)swFeatureScope_e.swFeatureScope_SelectedBodiesWithAutoSelect;

// Specify which bodies are affected
var body1 = GetBodyByName(swModel, "Body1");  // ... helper method
var body2 = GetBodyByName(swModel, "Body2");
mirrorData2.FeatureScopeBodies = new object[] { body1, body2 };
// NOTE: Cannot set to null if feature was created with scope bodies

mirrorFeature2.ModifyDefinition(mirrorData2, swModel, null);
