    true,      // Closed
    true,      // KeepTangency
    false,     // ForceNonRational  
    1.0,       // TessToleranceFactor
    0, 0,      // No tangency constraints
    1.0, 1.0,  // Tangent lengths (unused)
    true, true, // Tangent directions (unused)
    true,      // IsThinBody=TRUE (enable thin wall)
