    1,         // ThinType=1: swThinWallOppDirection (one direction reverse)
    true,      // Merge
    false,     // UseFeatScope
    true,      // UseAutoSelect
    (int)swGuideCurveInfluence_e.swGuideCurveInfluenceNextEdge
);

