    Debug.Assert(loftData.ThinWallType == 1);  // swThinWallOppDirection

    // For ThinType=1, reverse direction has the thickness
    double reverseWall = loftData.GetWallThickness(false);  // Returns 0.005
    double forwardWall = loftData.GetWallThickness(true);   // Returns 0.0

    Debug.Print($"Reverse wall: {reverseWall}m, Forward wall: {forwardWall}m");
}

