// Example: Create boss loft with Merge=true in multibody part
// When Merge=true, the loft body merges with all intersecting existing bodies

ModelDoc2 part = swApp.ActiveDoc as ModelDoc2;
FeatureManager featureMgr = part.FeatureManager;
ModelDocExtension docExt = part.Extension;

// Clear any existing selections
part.ClearSelection2(true);

// Select first profile (mark=1)
docExt.SelectByID2("Sketch1", "SKETCH", 0.07, 0, 0, false, 1, null, 0);

// Select second profile (mark=1, append=true)
docExt.SelectByID2("Sketch2", "SKETCH", 0.05, 0, 0.07, true, 1, null, 0);

// Select guide curves with correct marks:
// First guide curve: mark=4098 (2 + 4096*1)
docExt.SelectByID2("Curve1", "REFERENCECURVES", 0.1, 0.045, 0.128, true, 4098, null, 0);
// Second guide curve: mark=8194 (2 + 4096*2)
docExt.SelectByID2("Curve2", "REFERENCECURVES", 0.038, 0.022, 0.115, true, 8194, null, 0);
// Third guide curve: mark=12290 (2 + 4096*3)
docExt.SelectByID2("Curve3", "REFERENCECURVES", 0.1, -0.0007, 0.131, true, 12290, null, 0);
// Fourth guide curve: mark=16386 (2 + 4096*4)
docExt.SelectByID2("Curve4", "REFERENCECURVES", 0.159, 0.022, 0.129, true, 16386, null, 0);

// Optional: Select centerline (mark=4)
// docExt.SelectByID2("Curve5", "REFERENCECURVES", 0.1, 0.022, 0.108, true, 4, null, 0);

// Create loft with Merge=true
// UseFeatureScope=false means merge applies to ALL intersecting bodies
IFeature loftFeat = featureMgr.InsertProtrusionBlend2(
    false,  // Open loft
    true,   // Keep tangency
    false,  // Not forcing non-rational
    1.0,    // Default tessellation tolerance
    0, 0,   // No start/end tangency constraints
    1, 1,   // Default tangent lengths
    true, true,  // Tangent directions
    false,  // Not a thin body
    0, 0, 0,  // No thickness values
    true,   // MERGE=TRUE: Merges loft with ALL existing intersecting bodies
    false,  // UseFeatureScope=false: Affects all bodies (standard merge)
    true,   // UseAutoSelect (ignored when UseFeatureScope=false)
    (int)swGuideCurveInfluence_e.swGuideCurveInfluenceNextEdge
);

if (loftFeat != null)
{
    // Verify merge setting on the feature definition
    ILoftFeatureData loftDef = (ILoftFeatureData)loftFeat.GetDefinition();
    Debug.Assert(loftDef.Merge == true, "Merge should be true");

    // Note: If existing bodies intersected the loft, they are now merged
    // If no bodies existed, this creates the first body in the part
    Debug.WriteLine("Loft created with Merge=true");
}

