        // Must manually release selection access if ModifyDefinition failed
        chamferData.ReleaseSelectionAccess();
    }

} catch (Exception ex) {
    // Must manually release selection access on exception
    chamferData.ReleaseSelectionAccess();
    throw;
}

// Key Properties and Methods:
// - Type: Integer accepting swChamferType_e values (1, 2, or 3)
// - SetEdgeChamferDistance(side, distance): side 0-1 for distance-distance; distance in meters
// - EqualDistance: Boolean; when true, only side 0 distance is used for both sides
// - EdgeChamferAngle: Double; IGNORED for distance-distance chamfers (only for angle-distance)
// - Edges: Object[] of IEdge; accessible after AccessSelections; preserved when changing type
// - AccessSelections(TopDoc, Component): Required before reading/modifying geometric entities
// - ReleaseSelectionAccess(): Manually called only if ModifyDefinition not called or fails
// - ModifyDefinition(Data, TopDoc, Component): Returns true on success; auto-releases on success

// Properties NOT typically modified when changing chamfer type:
// - Edges: Edge selections are preserved from original chamfer
// - Faces: Face selections are preserved
// - Loops: Loop selections are preserved
// - KeepFeatures: Boolean; whether to keep features on selected entities
// - TangentPropagation: Boolean; whether to propagate to tangent faces
// - PropagateFeatureToParts: Boolean; assembly-level propagation option
// - GetIsFlipped(entity): Boolean per edge/face/loop; flip states preserved

// Properties only for vertex chamfer (Type = 3), IGNORED here:
// - Vertex, IVertex: The vertex to chamfer
// - SetVertexChamferDistance(side, distance): side 0-2 for three edges of vertex
// - GetVertexChamferDistance(side): Retrieve vertex distance for given side
