```csharp
// Example 1: Convert angle-distance chamfer to distance-distance with different distances
public bool ModifyChamferToDistanceDistance(
    IFeature chamferFeature, 
    IModelDoc2 swModel,
    double distance1, 
    double distance2)
{
    // Get chamfer definition
    IChamferFeatureData2 chamferData = (IChamferFeatureData2)chamferFeature.GetDefinition();

    // Access selections (required before modifying)
    if (!chamferData.AccessSelections(swModel, null)) {
        return false;
    }

    try {
        // Change type to distance-distance
        chamferData.Type = (int)swChamferType_e.swChamferDistanceDistance; // 2

        // Set different distances for each side
        chamferData.SetEdgeChamferDistance(0, distance1); // e.g., 0.010 meters (10mm)
        chamferData.SetEdgeChamferDistance(1, distance2); // e.g., 0.015 meters (15mm)
        chamferData.EqualDistance = false; // Use different distances

        // Apply modifications
        bool success = chamferFeature.ModifyDefinition(chamferData, swModel, null);

        if (!success) {
            // Check error and manually release
            bool warning;
            int errorCode = chamferFeature.GetErrorCode2(out warning);
            Debug.Print($"Modify failed. Error: {errorCode}, Warning: {warning}");
            chamferData.ReleaseSelectionAccess();
            return false;
        }

        // Success - ModifyDefinition automatically released selection access
        return true;

    } catch (Exception ex) {
        Debug.Print($"Exception: {ex.Message}");
        chamferData.ReleaseSelectionAccess();
        return false;
    }
}

// Example 2: Convert to distance-distance with equal distances (symmetric)
public bool ModifyChamferToEqualDistances(
    IFeature chamferFeature,
    IModelDoc2 swModel,
    double distance)
{
    IChamferFeatureData2 chamferData = (IChamferFeatureData2)chamferFeature.GetDefinition();

    if (!chamferData.AccessSelections(swModel, null)) {
        return false;
    }

    try {
        chamferData.Type = (int)swChamferType_e.swChamferDistanceDistance;
        chamferData.EqualDistance = true; // Both sides use same distance
        chamferData.SetEdgeChamferDistance(0, distance); // Only side 0 needed when EqualDistance=true
        // Side 1 value is ignored when EqualDistance=true

        bool success = chamferFeature.ModifyDefinition(chamferData, swModel, null);
        if (!success) {
            chamferData.ReleaseSelectionAccess();
            return false;
        }
        return true;

    } catch {
        chamferData.ReleaseSelectionAccess();
        return false;
    }
}

// Example 3: Modify existing chamfer and preserve edge selections
public bool ModifyPreservingEdges(
    IFeature chamferFeature,
    IModelDoc2 swModel)
{
    IChamferFeatureData2 chamferData = (IChamferFeatureData2)chamferFeature.GetDefinition();
    chamferData.AccessSelections(swModel, null);

    try {
        // Get current edges (optional - they're preserved automatically)
        object[] edges = (object[])chamferData.Edges;
        Debug.Print($"Chamfer has {edges.Length} edges");

        // Modify to distance-distance
        chamferData.Type = (int)swChamferType_e.swChamferDistanceDistance;
        chamferData.EqualDistance = false;
        chamferData.SetEdgeChamferDistance(0, 0.008);
        chamferData.SetEdgeChamferDistance(1, 0.012);

        // Edges are preserved - no need to re-set
        bool success = chamferFeature.ModifyDefinition(chamferData, swModel, null);
        if (!success) {
            chamferData.ReleaseSelectionAccess();
        }
        return success;

    } catch {
        chamferData.ReleaseSelectionAccess();
        return false;
    }
}
