// Example 1: Modify offset distance of a constraint-based reference plane
IFeature feature = swSelMgr.GetSelectedObject6(1, -1);
IRefPlaneFeatureData refPlaneData = (IRefPlaneFeatureData)feature.GetDefinition();

// Check if plane is constraint-based
if (refPlaneData.Type2 == (int)swRefPlaneType_e.swRefPlaneConstraintBase)
{
    // Check if it's a distance-based constraint plane
    if (refPlaneData.Type == (int)swRefPlaneType_e.swRefPlaneDistance)
    {
        refPlaneData.Distance = 0.1;  // Set offset to 100mm
    }
    else if (refPlaneData.Type == (int)swRefPlaneType_e.swRefPlaneAngle)
    {
        refPlaneData.Angle = 0.7853981;  // Set angle to 45 degrees
    }
}

feature.ModifyDefinition(refPlaneData, swModel, null);

// Example 2: Update plane to be parallel to screen
IRefPlaneFeatureData refPlaneData = (IRefPlaneFeatureData)feature.GetDefinition();
refPlaneData.UpdatePlane = true;
feature.ModifyDefinition(refPlaneData, swModel, null);

// Example 3: Read selections (constraint-based planes - read-only)
IRefPlaneFeatureData refPlaneData = (IRefPlaneFeatureData)feature.GetDefinition();

// Enter rollback state to access selections
refPlaneData.AccessSelections(swModel, null);

// Get current selections (read-only for constraint-based planes)
int selCount = refPlaneData.GetSelectionsCount();
object[] selections = refPlaneData.Selections;

// Release access
refPlaneData.ReleaseSelectionAccess();

// Example 4: Modify non-constraint-based plane properties with indexed access
IRefPlaneFeatureData refPlaneData = (IRefPlaneFeatureData)feature.GetDefinition();

// For non-constraint-based planes, use indexed properties
if (refPlaneData.Type2 != (int)swRefPlaneType_e.swRefPlaneConstraintBase)
{
    refPlaneData.AccessSelections(swModel, null);

    // Modify first reference
    refPlaneData.AngleOrDistance[0] = 0.1;  // swRefPlaneReference_First = 0
    refPlaneData.ReversedReferenceDirection[0] = true;

    feature.ModifyDefinition(refPlaneData, swModel, null);
}

