// NOTE: Tool body sweeps require SOLIDWORKS API 2017 FCS or later
// Tool body constraints: must be convex, not merged with main body, and consist of:
//   - Revolved feature with analytical geometry only (lines and arcs), OR
//   - Cylindrical extruded feature

// CRITICAL: Make selections in this specific order with these exact mark values:
// Mark 1 = Tool body (the solid that will sweep along the path to cut material)
// Mark 4 = Path (sketch or curve defining the sweep path)
// Mark 2048 = Target body (the solid to be cut)
model.ClearSelection2(true);
bool ok = modelExtension.SelectByID2("ToolBodyName", "SOLIDBODY", 0, 0, 0, false, 1, null, 0);  // Mark 1
ok = modelExtension.SelectByID2("PathSketch", "SKETCH", 0, 0, 0, true, 4, null, 0);            // Mark 4
ok = modelExtension.SelectByID2("TargetBody", "SOLIDBODY", 0, 0, 0, true, 2048, null, 0);      // Mark 2048

// Create sweep cut feature definition
ISweepFeatureData sweepData = featureMgr.CreateDefinition(swFmSweepCut);

// Configure sweep feature properties
sweepData.TangentPropagation = false;  // Boolean
sweepData.AlignWithEndFaces = true;     // Boolean - alignment behavior may differ with tool body
sweepData.TwistControlType = 0;         // swTwistControlType_e (0=Follow Path) - limited applicability with tool body
sweepData.MaintainTangency = false;     // Boolean
sweepData.AdvancedSmoothing = false;    // Boolean
sweepData.StartTangencyType = 0;        // swTangencyType_e (0=None) - limited applicability with tool body
sweepData.EndTangencyType = 0;          // swTangencyType_e (0=None) - limited applicability with tool body  
sweepData.ThinFeature = false;          // Boolean - set to true for thin-walled cuts
sweepData.SetWallThickness(true, 0.0);  // Direction 1 thickness (only if ThinFeature = true)
sweepData.SetWallThickness(false, 0.0); // Direction 2 thickness (only if ThinFeature = true)
sweepData.ThinWallType = 0;             // swThinWallType_e (0=1D, 1=1DReverse, 2=MidPlane, 3=2D) - only if ThinFeature = true
sweepData.PathAlignmentType = 0;        // swTangencyType_e - path alignment type
sweepData.FeatureScope = true;          // Boolean - use scope in multibody part
sweepData.AutoSelect = false;           // Boolean - IMPORTANT: false for swept-cut to control target body selection via mark 2048
sweepData.SetTwistAngle(0.0);           // Twist angle (only if TwistControlType = swTwistControlConstantTwistAlongPath)
sweepData.MergeSmoothFaces = true;      // Boolean - merge smooth faces if using guide curves
sweepData.CircularProfile = false;      // Boolean - MUST be false for tool body sweeps
sweepData.CircularProfileDiameter = 0.0; // Ignored when CircularProfile = false
