// Complete example: Create a swept-cut feature using a tool body
// Requirements: SOLIDWORKS API 2017 FCS or later
// Tool body constraints: convex, not merged, revolved (analytical geometry) or cylindrical extruded

// Assume: swModel has:
//  - Target solid body to be cut (e.g., "Boss-Extrude1") 
//  - Tool body - a revolved or cylindrical extruded feature (e.g., "Revolve1")
//  - Sketch defining the sweep path (e.g., "Sketch2")

// Step 1: Make selections in SPECIFIC ORDER with SPECIFIC MARKS:
//   Mark 1 = Tool body (profile)
//   Mark 4 = Sweep path 
//   Mark 2048 = Target body to cut
model.ClearSelection2(true);
bool ok = modelExtension.SelectByID2("Revolve1", "SOLIDBODY", 0, 0, 0, false, 1, null, 0);       // Tool body
ok = modelExtension.SelectByID2("Sketch2", "SKETCH", 0, 0, 0, true, 4, null, 0);                 // Path
ok = modelExtension.SelectByID2("Boss-Extrude1", "SOLIDBODY", 0, 0, 0, true, 2048, null, 0);    // Target

// Step 2: Create sweep cut definition
ISweepFeatureData sweep = featureMgr.CreateDefinition(swFmSweepCut);

// Step 3: Configure for tool body sweep
sweep.TangentPropagation = false;
sweep.AlignWithEndFaces = true;
sweep.TwistControlType = 0;      // Follow Path
sweep.MaintainTangency = false;
sweep.AdvancedSmoothing = false;
sweep.StartTangencyType = 0;
sweep.EndTangencyType = 0;
sweep.ThinFeature = false;
sweep.PathAlignmentType = 0;
sweep.FeatureScope = true;
sweep.AutoSelect = false;         // CRITICAL: false to use explicit target body selection (mark 2048)
sweep.CircularProfile = false;    // MUST be false for tool body
sweep.Direction = 0;              // swSweepDirection1

// Step 4: Create the feature
IFeature sweptCut = featureMgr.CreateFeature(sweep);

// Step 5: Verify it's a solid sweep (tool body)
//   Access feature definition to inspect properties
ISweepFeatureData data = (ISweepFeatureData)sweptCut.GetDefinition();
status = data.AccessSelections(swModel, null);

//   Check cut type: should be 2 (swSolidSweep) for tool body
int cutType = data.GetCutSweepOption();
if (cutType == 2)  // swSolidSweep from swCutSweepOption_e
{
    //   Get the tool body
    object profileObj = data.Profile;
    IBody2 toolBody = (IBody2)profileObj;
    Debug.WriteLine("Tool body: " + toolBody.Name);

    //   Get the path
    IFeature pathFeature = data.Path;
    Debug.WriteLine("Path: " + pathFeature.Name);

    //   Get profile type (should return swSelSOLIDBODIES)
    int profileType = data.GetProfileType();
}

data.ReleaseSelectionAccess();

