// Example: Create edge draft with propagation to tangent faces sharing neutral plane
using SolidWorks.Interop.sldworks;
using SolidWorks.Interop.swconst;

ModelDoc2 swModel = swApp.ActiveDoc;
IModelDocExtension swDocExt = swModel.Extension;
IFeatureManager featureMgr = swModel.FeatureManager;

// Clear any existing selections
swModel.ClearSelection2(true);

// EDGE DRAFT SELECTION SEQUENCE:
// 1. Select direction reference with mark=1 (e.g., bottom face serves as direction/neutral plane)
swDocExt.SelectByID2("Face@[PartBody][1]", "FACE", 0, 0, 0, false, 1, null, 0);

// 2. Select edges to draft with mark=4 (SOLIDWORKS will find adjacent faces)
swDocExt.SelectByID2("Edge@[PartBody][1]", "EDGE", 0, 0, 0, true, 4, null, 0);
swDocExt.SelectByID2("Edge@[PartBody][2]", "EDGE", 0, 0, 0, true, 4, null, 0);

// 3. Create the edge draft with tangent propagation
double angleRadians = System.Math.PI / 18.0; // 10 degrees
Feature draftFeature = featureMgr.InsertMultiFaceDraft(
    angle: angleRadians,
    flipDir: false,
    edgeDraft: true,              // TRUE = edge draft mode (select edges, not faces)
    propType: 1,                  // Propagate to tangent faces sharing neutral plane
                                  // (valid for edge draft mode)
    isStepDraft: false,
    isBodyDraft: false
);

if (draftFeature != null)
{
    // Access feature data (read-only without AccessSelections)
    DraftFeatureData2 draftData = (DraftFeatureData2)draftFeature.GetDefinition();
    System.Diagnostics.Debug.WriteLine("Draft angle: " + draftData.Angle + " radians");
    System.Diagnostics.Debug.WriteLine("Face propagation type: " + draftData.FacePropagation);
    System.Diagnostics.Debug.WriteLine("Draft type: " + draftData.Type); // Should be 0 (neutral plane)
}
