// Select faces to draft with mark 2
boolStatus = swDocExt.SelectByID2("Face1@Boss1", "FACE", 0, 0, 0, true, 2, null, 0);
boolStatus = swDocExt.SelectByID2("Face2@Boss1", "FACE", 0, 0, 0, true, 2, null, 0);

