// Example: Create a perpendicular step draft on a selected face
ModelDoc2 swModel = (ModelDoc2)swApp.ActiveDoc;
IFeatureManager featureMgr = swModel.FeatureManager;
IModelDocExtension modelDocExt = (IModelDocExtension)swModel;

// PHASE 1: Create the step draft feature
// Pre-select the direction face (selection mark 1) and face to draft (selection mark 2)
modelDocExt.SelectByID2("Face1@Part1", "FACE", 0, 0, 0, false, 1, null, 0);
modelDocExt.SelectByID2("Face2@Part1", "FACE", 0, 0, 0, true, 2, null, 0);

// Create the step draft (StepType will need to be set in Phase 2)
double draftAngle = Math.PI / 18;  // 10 degrees in radians
Feature stepDraftFeature = featureMgr.InsertMultiFaceDraft(
    draftAngle,     // Angle in radians
    false,          // Don't flip direction
    false,          // Face draft (not edge draft)
    0,              // No face propagation (swFacePropNone)
    true,           // This is a step draft
    false           // Not a body draft
);

if (stepDraftFeature == null) {
    Debug.Print("Failed to create step draft feature");
    return;
}

// PHASE 2: Set the perpendicular step type
// Get the feature definition
IDraftFeatureData2 draftData = (IDraftFeatureData2)stepDraftFeature.GetDefinition();

// CRITICAL: Access selections before modifying
if (!draftData.AccessSelections(swModel, null)) {
    Debug.Print("Failed to access selections");
    return;
}

// Set the step type to perpendicular
draftData.StepType = (short)swDraftStepType_e.swDraftPerpendicular;

// CRITICAL: Apply changes and restore rollback state
if (!stepDraftFeature.ModifyDefinition(draftData, swModel, null)) {
    Debug.Print("Failed to modify step draft definition");
    int errorCode = stepDraftFeature.GetErrorCode2();
    Debug.Print($"Error code: {errorCode}");
    return;
}

// Verify the step draft was created correctly
