if (draftData.Type == (int)swDraftType_e.swStepDraft &&
    draftData.StepType == (short)swDraftStepType_e.swDraftPerpendicular)
{
    Debug.Print("Perpendicular step draft created successfully");
    Debug.Print($"Angle: {draftData.Angle * 180 / Math.PI} degrees");
    Debug.Print($"Face propagation: {draftData.FacePropagation}");
}

// Note: No need to call ReleaseSelectionAccess after ModifyDefinition
